#include <stdio.h>
int main() {
	int c1,c2,c3,c4,c5;
	scanf("%d %d %d %d %d",&c1,&c2,&c3,&c4,&c5);
	int S=c1+c2+c3+c4+c5;
	if(c1==c2&&c2==c3&&c3==c4&&c4==c5&&c1==0) S=1;
	if(S%5!=0) printf("-1");
	else printf("%d",S/5);
	return 0;
}

