fn main() {
    let mut s = String::new();
    std::io::stdin().read_line(&mut s).unwrap();
    let size = s.split_whitespace().map(|x| x.parse::<i32>().unwrap()).collect::<Vec<i32>>();
    let mut c = -1;
    if size.iter().fold(true, |acc, &x| acc && (x==0)) == true {
        c=-1;
    } else {
    for i  in 0..=100 {
        if size.iter().map(|x| x-i).sum::<i32>() == 0 {
           c = i;
           break;
        }
    }
    }
    println!("{}",c );
}
